import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"🫘 黃豆追蹤日誌 — 2026-05-01（週五）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-01.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-01.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-01.md"};function n(o,t,s,d,h,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="🫘-黃豆追蹤日誌-—-2026-05-01-週五" tabindex="-1">🫘 黃豆追蹤日誌 — 2026-05-01（週五） <a class="header-anchor" href="#🫘-黃豆追蹤日誌-—-2026-05-01-週五" aria-label="Permalink to &quot;🫘 黃豆追蹤日誌 — 2026-05-01（週五）&quot;">​</a></h1><blockquote><p>掃描時間：Gale 指令觸發（Telegram） 資料來源：web_search (Google Search grounding)</p></blockquote><hr><h2 id="🗞️-5-條今日黃豆相關新聞" tabindex="-1">🗞️ 5 條今日黃豆相關新聞 <a class="header-anchor" href="#🗞️-5-條今日黃豆相關新聞" aria-label="Permalink to &quot;🗞️ 5 條今日黃豆相關新聞&quot;">​</a></h2><h3 id="新聞-1-cbot-黃豆期貨創六週新高-月漲-1-89" tabindex="-1">新聞 1：CBOT 黃豆期貨創六週新高，月漲 1.89% <a class="header-anchor" href="#新聞-1-cbot-黃豆期貨創六週新高-月漲-1-89" aria-label="Permalink to &quot;新聞 1：CBOT 黃豆期貨創六週新高，月漲 1.89%&quot;">​</a></h3><p>5/1 CBOT 黃豆升至 <strong>1,185.53 美分/蒲式耳</strong>（+0.30%），月漲 1.89%，年漲 13.04%。阿根廷收割延遲及生質燃料需求推升。 <em>來源：web_search (TradingEconomics)</em></p><h3 id="新聞-2-巴西大豆產量預估-1-778-1-781-億噸創紀錄" tabindex="-1">新聞 2：巴西大豆產量預估 1.778-1.781 億噸創紀錄 <a class="header-anchor" href="#新聞-2-巴西大豆產量預估-1-778-1-781-億噸創紀錄" aria-label="Permalink to &quot;新聞 2：巴西大豆產量預估 1.778-1.781 億噸創紀錄&quot;">​</a></h3><p>Conab 4 月預測 <strong>1.7785 億噸</strong>，Safras &amp; Mercado 預測 <strong>1.7811 億噸</strong>。種植面積約 4,900 萬公頃創新高。但農民利潤率受低價和高成本擠壓。 <em>來源：web_search (thepoultrysite, farmdocdaily Illinois, Agrolatam)</em></p><h3 id="新聞-3-阿根廷產量上修至-4-860-萬噸" tabindex="-1">新聞 3：阿根廷產量上修至 4,860 萬噸 <a class="header-anchor" href="#新聞-3-阿根廷產量上修至-4-860-萬噸" aria-label="Permalink to &quot;新聞 3：阿根廷產量上修至 4,860 萬噸&quot;">​</a></h3><p>布宜諾斯艾利斯穀物交易所將 2025/26 產量預估上調至 <strong>4,860 萬噸</strong>，優於預期。儘管種植面積減少，但產量優於預期。阿根廷黃豆出口預估年增 5% 至 820 萬噸（2019/20 以來最高）。 <em>來源：web_search (AgroReview, UkrAgroConsult)</em></p><h3 id="新聞-4-巴西-2026-年出口預估創紀錄-1-136-億噸" tabindex="-1">新聞 4：巴西 2026 年出口預估創紀錄 1.136 億噸 <a class="header-anchor" href="#新聞-4-巴西-2026-年出口預估創紀錄-1-136-億噸" aria-label="Permalink to &quot;新聞 4：巴西 2026 年出口預估創紀錄 1.136 億噸&quot;">​</a></h3><p>儘管創紀錄出口量，但均價從 $440/噸下修至 $370/噸，出口收入反可能減少。生質燃料強制令正在吸收更多大豆供應。 <em>來源：web_search (Agrolatam, S&amp;P Global, farmdocdaily)</em></p><h3 id="新聞-5-中美貿易不確定性壓抑黃豆需求前景" tabindex="-1">新聞 5：中美貿易不確定性壓抑黃豆需求前景 <a class="header-anchor" href="#新聞-5-中美貿易不確定性壓抑黃豆需求前景" aria-label="Permalink to &quot;新聞 5：中美貿易不確定性壓抑黃豆需求前景&quot;">​</a></h3><p>IEEPA 關稅退款 5/11 啟動，但 Section 122 全球 10% 關稅持續至 7/24。中國 25 Mt 採購承諾在不確定關稅環境下難實現。南美仍為中國主要大豆供應來源。 <em>來源：web_search (Economictimes, S&amp;P Global)</em></p><hr><h2 id="📋-8-項追蹤指標檢查結果" tabindex="-1">📋 8 項追蹤指標檢查結果 <a class="header-anchor" href="#📋-8-項追蹤指標檢查結果" aria-label="Permalink to &quot;📋 8 項追蹤指標檢查結果&quot;">​</a></h2><h3 id="✅-指標-1-usda-種植進度報告" tabindex="-1">✅ 指標 1：USDA 種植進度報告 <a class="header-anchor" href="#✅-指標-1-usda-種植進度報告" aria-label="Permalink to &quot;✅ 指標 1：USDA 種植進度報告&quot;">​</a></h3><p><strong>狀態：有變化 ⚠️（維持快速）</strong></p><ul><li>3/31 Prospective Plantings：黃豆 <strong>8,470 萬英畝</strong>（+4%），玉米 <strong>9,530 萬英畝</strong>（-3%）</li><li>截至 4/26：黃豆已種植 <strong>23%</strong>（五年平均 12%）</li><li>下份 Crop Progress 預計 5/5 公布 <em>來源：web_search (USDA NASS, Farm Policy News Illinois)</em></li></ul><h3 id="✅-指標-2-巴西供應-收割-出口-豐收" tabindex="-1">✅ 指標 2：巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#✅-指標-2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;✅ 指標 2：巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><p><strong>狀態：無重大變化</strong></p><ul><li>產量 <strong>1.778-1.781 億噸</strong>（創紀錄，月中旬已確認）</li><li>出口預估 <strong>1.136 億噸</strong>（創紀錄，均價下修至 $370/噸）</li><li>農民利潤率受壓，檔口溢價疲弱 <em>來源：web_search (Conab, Safras, farmdocdaily Illinois)</em></li></ul><h3 id="✅-指標-3-尿素價格-多單訊號" tabindex="-1">✅ 指標 3：尿素價格 + 多單訊號 <a class="header-anchor" href="#✅-指標-3-尿素價格-多單訊號" aria-label="Permalink to &quot;✅ 指標 3：尿素價格 + 多單訊號&quot;">​</a></h3><p><strong>狀態：有變化 🔴 仍高於 $700 歷史高檔區</strong></p><ul><li>基準尿素約 <strong>$694-866/噸</strong>區間（4 月高點）</li><li>World Bank 預測 2026 年肥料價格漲超 <strong>30%</strong></li><li>荷莫茲封閉影響全球約 <strong>40% 尿素出口</strong></li><li>🚨 多單訊號有效 <em>來源：web_search (Metals Hub, World Bank)</em></li></ul><h3 id="✅-指標-4-荷莫茲海峽通航狀態" tabindex="-1">✅ 指標 4：荷莫茲海峽通航狀態 <a class="header-anchor" href="#✅-指標-4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;✅ 指標 4：荷莫茲海峽通航狀態&quot;">​</a></h3><p><strong>狀態：持續封閉 🔴 最高風險</strong></p><ul><li>第 <strong>63 天</strong>封閉，伊朗最高領袖 5/1 強硬表態</li><li>全球約 1/3 海運肥料貿易、<strong>40% 尿素出口</strong>受阻</li><li>短期無重開跡象 <em>來源：web_search (Wikipedia 2026 Hormuz Crisis, The Guardian)</em></li></ul><h3 id="✅-指標-5-中美貿易-中國進口" tabindex="-1">✅ 指標 5：中美貿易 + 中國進口 <a class="header-anchor" href="#✅-指標-5-中美貿易-中國進口" aria-label="Permalink to &quot;✅ 指標 5：中美貿易 + 中國進口&quot;">​</a></h3><p><strong>狀態：有變化 🟡</strong></p><ul><li>IEEPA 關稅退款 <strong>$1,660 億</strong>預計 5/11 發放</li><li>Section 122 全球 10% 關稅至 7/24 到期</li><li>中國續擴非洲貿易（5/1 零關稅 53 國）</li><li>25 Mt 黃豆採購承諾在不確定關稅環境下難實現 <em>來源：web_search (Economictimes, S&amp;P Global)</em></li></ul><h3 id="✅-指標-6-天然氣價格" tabindex="-1">✅ 指標 6：天然氣價格 <a class="header-anchor" href="#✅-指標-6-天然氣價格" aria-label="Permalink to &quot;✅ 指標 6：天然氣價格&quot;">​</a></h3><p><strong>狀態：有變化 🟢 低檔</strong></p><ul><li>5/1 Henry Hub <strong>$2.635/MMBtu</strong>（+1.3%）</li><li>歐洲 TTF 近數週暴漲近 45%</li><li>低檔天然氣部分緩解尿素成本壓力 <em>來源：web_search (FX Daily Report, NGI)</em></li></ul><h3 id="✅-指標-7-聖嬰-拉尼娜氣候風險" tabindex="-1">✅ 指標 7：聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#✅-指標-7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;✅ 指標 7：聖嬰/拉尼娜氣候風險&quot;">​</a></h3><p><strong>狀態：無重大變化</strong></p><ul><li>La Niña 減弱中，ENSO 中性</li><li>聖嬰可能 5-7 月出現（機率 61%-62%） <em>來源：web_search (NOAA CPC, IRI)</em></li></ul><h3 id="✅-指標-8-cbot-價格區間" tabindex="-1">✅ 指標 8：CBOT 價格區間 <a class="header-anchor" href="#✅-指標-8-cbot-價格區間" aria-label="Permalink to &quot;✅ 指標 8：CBOT 價格區間&quot;">​</a></h3><p><strong>狀態：有變化 🟡 六週新高</strong></p><ul><li>5/1 <strong>1,185.53 美分/蒲式耳</strong>（+0.30%），年漲 13.04%</li><li>Trading Economics 預測 12 個月目標 <strong>1,225.89 美分</strong>（突破 1,200 閾值）</li><li>目前 1,185 接近 1,200，<strong>尚未觸發</strong><em>來源：web_search (TradingEconomics)</em></li></ul><hr><h2 id="📊-綜合評估" tabindex="-1">📊 綜合評估 <a class="header-anchor" href="#📊-綜合評估" aria-label="Permalink to &quot;📊 綜合評估&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">#</th><th style="text-align:left;">指標</th><th style="text-align:center;">狀態</th><th style="text-align:center;">方向</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">USDA 種植 23%</td><td style="text-align:center;">⚠️ 快速超前</td><td style="text-align:center;">利多</td><td style="text-align:left;">USDA</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">巴西創紀錄豐收</td><td style="text-align:center;">無重大變化</td><td style="text-align:center;">利空</td><td style="text-align:left;">Conab</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">尿素 $694+ / 多單</td><td style="text-align:center;">🔴 高檔</td><td style="text-align:center;">利空</td><td style="text-align:left;">Metals Hub</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">荷莫茲 63 天</td><td style="text-align:center;">🔴 封閉</td><td style="text-align:center;">利空</td><td style="text-align:left;">Wikipedia</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;">中美貿易</td><td style="text-align:center;">🟡 關稅退款 5/11</td><td style="text-align:center;">偏多</td><td style="text-align:left;">Economictimes</td></tr><tr><td style="text-align:center;">6</td><td style="text-align:left;">天然氣 $2.635</td><td style="text-align:center;">🟢 低檔</td><td style="text-align:center;">利多</td><td style="text-align:left;">FX Daily</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:left;">氣候風險</td><td style="text-align:center;">無變化</td><td style="text-align:center;">不確定</td><td style="text-align:left;">NOAA</td></tr><tr><td style="text-align:center;">8</td><td style="text-align:left;">CBOT 1,185.53</td><td style="text-align:center;">🟡 六週新高</td><td style="text-align:center;">偏多</td><td style="text-align:left;">TradingEconomics</td></tr></tbody></table><p><strong>多空平衡：偏多（六週新高 + 阿根廷延遲 + 生質燃料需求 vs 荷莫茲成本壓力）</strong></p><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>web_search: CBOT 1,185.53 六週新高 | TradingEconomics</li><li>web_search: 巴西產量 1.778-1.781 億噸創紀錄 | thepoultrysite, farmdocdaily Illinois, Agrolatam</li><li>web_search: 阿根廷產量上修至 4,860 萬噸 | AgroReview, UkrAgroConsult</li><li>web_search: 巴西出口創紀錄 1.136 億噸 | Agrolatam, S&amp;P Global</li><li>web_search: 中美貿易不確定 + 關稅退款 | Economictimes, S&amp;P Global</li><li>web_search: USDA 種植進度 | USDA NASS, Farm Policy News Illinois</li><li>web_search: 尿素價格 | Metals Hub, World Bank</li><li>web_search: 荷莫茲第 63 天 | Wikipedia, The Guardian</li><li>web_search: 天然氣 $2.635 | FX Daily Report, NGI</li><li>web_search: ENSO中性+聖嬰預測 | NOAA CPC, IRI</li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 模型：local/Qwen3.6-35B-A3B-4bit</em></p>',49)])])}const b=e(i,[["render",n]]);export{m as __pageData,b as default};
